/**
 * Recursively flattens a configuration node from xml2js format
 * into a cleaner JavaScript object.
 */
function flattenConfigNode(node) {
  if (typeof node === 'string') return node;
  if (node === null || node === undefined) return null;

  const result = {};

  // Handle attributes
  if (node.$ && typeof node.$ === 'object') {
    result._attributes = { ...node.$ };
  }

  // Handle text content
  if (node._ !== undefined) {
    result._text = node._;
  }

  for (const [key, value] of Object.entries(node)) {
    if (key === '$' || key === '_' || key === '$$') continue;

    if (Array.isArray(value)) {
      if (value.length === 1) {
        const item = value[0];
        if (typeof item === 'string') {
          result[key] = item;
        } else if (typeof item === 'object') {
          result[key] = flattenConfigNode(item);
        }
      } else {
        result[key] = value.map(item => {
          if (typeof item === 'string') return item;
          if (typeof item === 'object') return flattenConfigNode(item);
          return item;
        });
      }
    } else if (typeof value === 'string') {
      result[key] = value;
    } else if (typeof value === 'object') {
      result[key] = flattenConfigNode(value);
    }
  }

  // If the result only has a _text property, return just the text
  const resultKeys = Object.keys(result);
  if (resultKeys.length === 1 && resultKeys[0] === '_text') {
    return result._text;
  }

  return result;
}

